class Solution:
    def primePalindrome(self, n):
        def is_prime(x):
            if x < 2:
                return False
            if x % 2 == 0:
                return x == 2
            d = 3
            while d * d <= x:
                if x % d == 0:
                    return False
                d += 2
            return True
        if n <= 11:
            for p in (2, 3, 5, 7, 11):
                if p >= n:
                    return p
        half = 1
        while True:
            for root in range(10 ** (half - 1), 10 ** half):
                s = str(root)
                cand = int(s + s[:-1][::-1])
                if cand >= n and is_prime(cand):
                    return cand
            half += 1

