var primePalindrome = function(n) {
    function isPrime(x) {
        if (x < 2) return false;
        if (x % 2 === 0) return x === 2;
        for (let d = 3; d * d <= x; d += 2) {
            if (x % d === 0) return false;
        }
        return true;
    }
    if (n <= 11) {
        for (const p of [2, 3, 5, 7, 11]) if (p >= n) return p;
    }
    let half = 1;
    while (true) {
        const lo = Math.pow(10, half - 1), hi = Math.pow(10, half);
        for (let root = lo; root < hi; root++) {
            const s = String(root);
            const cand = Number(s + s.slice(0, -1).split('').reverse().join(''));
            if (cand >= n && isPrime(cand)) return cand;
        }
        half++;
    }
};
